mapper.select:
SELECT COUNT(*)
FROM log l



        AND (
            (l.type = 0) OR 
            (l.type = 1 AND EXISTS (
                SELECT 1 FROM repairman r WHERE r.id = l.user_id AND r.area_id = #{areaId}
            ))
        )



        AND l.type = #{type}



        AND l.status = #{status}



        AND l.operation_time >= FROM_UNIXTIME(#{operationTimeMin} / 1000)



        AND l.operation_time <= FROM_UNIXTIME(#{operationTimeMax} / 1000)

SELECT COUNT(*)
FROM log l


        AND (
            (l.type = 0) OR 
            (l.type = 1 AND EXISTS (
                SELECT 1 FROM repairman r WHERE r.id = l.user_id AND r.area_id = #{areaId}
            ))
        )

