SELECT COUNT(*)
FROM log l

    AND DATE(l.operation_time) = CURDATE()

        AND (
            (l.type = 0) OR 
            (l.type = 1 AND EXISTS (
                SELECT 1 FROM repairman r WHERE r.id = l.user_id AND r.area_id = #{areaId}
            ))
        )
